            aOrbiterC = (aOrbiterC + aOrbiterG) + 0x25A9B1C4F44D4A58ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterC) ^ 0x72CC16AAA299CC04ULL) ^ aPhaseAOrbiterUpdateSaltF[(((31U - aIndex) + 11U)) & S_SALT1];
