            aOrbiterD = (aOrbiterD + aOrbiterB) + 0xC74251A4B4A7DB98ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterD) ^ 0x9C114221136385EEULL;
            aOrbiterF = RotL64((aOrbiterF * 0xB47AFE3C22F2AA83ULL), 19U);
