            aOrbiterG = RotL64((aOrbiterG * 0xEC902285F8319685ULL), 13U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterF) + 0x5B3D6301A3150D77ULL) + aPhaseAOrbiterUpdateSaltA[((aIndex + 7U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 0x7092906DEF792C82ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xA48346BF992E4FEFULL), 27U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterE) + 0x59F3F1F8FB4850A3ULL) + aPhaseAOrbiterUpdateSaltF[(((31U - aIndex) + 8U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterG) ^ 0xADDE9C911F9F7345ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xB9CEDD6DE9885A25ULL), 57U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0x0DABF2BB02139E43ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterF) ^ 0x66514B312E9E252FULL;
            aOrbiterK = RotL64((aOrbiterK * 0x796A04B4D823F0C3ULL), 43U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterD) + 0x24BD39B45D3CE02CULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterH) ^ 0x9753358392631253ULL) ^ aPhaseAOrbiterUpdateSaltC[((aIndex + 3U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0x54B88EA91290FC87ULL), 23U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterK) + 0x2ACABF32981A7694ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterE) ^ 0x5886EBD0FD78966FULL) ^ aPhaseAOrbiterUpdateSaltB[((aIndex + 12U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x98D7D33A775B54F5ULL), 37U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 0x7C9FB5496ABAFEFCULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterK) ^ 0xC5DFC0CEE1829DD9ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x5F0A2F60855354B7ULL), 53U);
            //
            aIngress = aOrbiterD ^ RotL64(aOrbiterF, 39U);
            aIngress = aIngress + (RotL64(aOrbiterC, 57U) ^ aOrbiterA);
            aIngress = aIngress + (RotL64(aOrbiterG, 44U) ^ aOrbiterB);
            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterH, 53U));
            aIngress = aIngress + RotL64(aOrbiterK, 21U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererA = aWandererA + (((RotL64(aPrevious, 11U) + RotL64(aOrbiterH, 51U)) + aOrbiterA) + RotL64(aCarry, 39U));
            aWandererC = aWandererC ^ ((RotL64(aScatter, 52U) + aOrbiterC) + RotL64(aOrbiterK, 29U));
            aWandererJ = aWandererJ + (((RotL64(aCross, 35U) + aOrbiterB) + RotL64(aOrbiterF, 3U)) + RotL64(aCarry, 5U));
            aWandererD = aWandererD ^ ((RotL64(aIngress, 3U) + RotL64(aOrbiterA, 35U)) + aOrbiterF);
            aWandererI = aWandererI + (((RotL64(aPrevious, 47U) + aOrbiterA) + RotL64(aOrbiterG, 10U)) + aPhaseAWandererUpdateSaltD[((aIndex + 16U)) & S_SALT1]);
            aWandererB = aWandererB ^ ((RotL64(aCross, 23U) + RotL64(aOrbiterE, 39U)) + aOrbiterG);
            aWandererE = aWandererE + (((RotL64(aIngress, 41U) + aOrbiterE) + RotL64(aOrbiterD, 47U)) + aPhaseAWandererUpdateSaltE[(((31U - aIndex) + 11U)) & S_SALT1]);
            aWandererF = aWandererF ^ ((RotL64(aScatter, 30U) + aOrbiterG) + RotL64(aOrbiterK, 43U));
            aWandererH = aWandererH + ((RotL64(aIngress, 57U) + RotL64(aOrbiterD, 58U)) + aOrbiterF);
