            aWandererC = aWandererC ^ ((RotL64(aPrevious, 29U) + RotL64(aOrbiterJ, 47U)) + aOrbiterC);
            aWandererJ = aWandererJ + ((RotL64(aScatter, 37U) + aOrbiterE) + RotL64(aOrbiterK, 20U));
